// ============================================
// BUDGET OPTIMIZER PRO v3.0 - Fully Dynamic
// All data from Meta API + PostgreSQL
// No hardcoded values
// ============================================

// ---- DATA SOURCES ----
const metaData = $('Fetch Ads').first().json;
const adSets = metaData.data || [];

// DB stats from previous node
const dbRaw = $input.first().json;
let stats = {};
try {
  const raw = dbRaw.stats || dbRaw;
  stats = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  stats = {};
}
const leadQuality = stats.lead_quality || {};
const budgetHistory = stats.budget_history || {};

// ---- CONFIGURATION ----
const CONFIG = {
  TARGET_CPL: 300,

  // Minimum data before any change
  MIN_LEADS: 5,
  MIN_SPEND_FACTOR: 3,

  // Cooldown & caps
  MIN_DAYS_SINCE_CHANGE: 5,
  MAX_WEEKLY_TOTAL_CHANGE: 30,

  // Dead zone
  NO_CHANGE_ZONE: 0.15,

  // Budget limits (Meta API uses cents/ore)
  MIN_DAILY_BUDGET: 5000,
  MAX_DAILY_BUDGET: 100000,
  MIN_CHANGE_AMOUNT: 1000,

  // Safety
  PAUSE_CPL_MULTIPLIER: 2.0
};

// ---- HELPER: Extract lead count from Meta insights ----
function getMetaLeads(insights) {
  const actions = insights?.actions || [];
  const leadTypes = [
    'lead',
    'onsite_conversion.lead_grouped',
    'offsite_conversion.fb_pixel_lead',
    'offsite_conversion.fb_pixel_custom'
  ];
  for (const a of actions) {
    if (leadTypes.includes(a.action_type)) {
      return parseInt(a.value) || 0;
    }
  }
  return 0;
}

// ---- HELPER: Match quality from DB (fuzzy Swedish match) ----
function matchQuality(svcKey, lq) {
  if (!lq || Object.keys(lq).length === 0) return null;
  const normalize = s => s.toLowerCase()
    .replace(/[\u00e5\u00e4]/g, 'a')
    .replace(/\u00f6/g, 'o')
    .replace(/[^a-z]/g, '');
  const target = normalize(svcKey);
  for (const [service, data] of Object.entries(lq)) {
    const s = normalize(service);
    if (s.includes(target) || target.includes(s)) {
      return data;
    }
  }
  return null;
}

// ---- HELPER: Check cooldown from budget history ----
function getCooldown(adName, bh, minDays) {
  for (const [key, data] of Object.entries(bh)) {
    if (adName.includes(key) || key.includes(adName)) {
      const days = (Date.now() - new Date(data.last_change).getTime()) / 86400000;
      return {
        days: Math.round(days * 10) / 10,
        count: parseInt(data.changes_7d) || 0,
        totalPct: parseFloat(data.total_pct) || 0,
        cooling: days < minDays
      };
    }
  }
  return { days: 999, count: 0, totalPct: 0, cooling: false };
}

// ---- MAIN OPTIMIZATION LOOP ----
const results = [];
const summary = [];

for (const ad of adSets) {
  if (ad.status !== 'ACTIVE') continue;

  const name = ad.name || 'UNKNOWN';
  const svc = name.split('_')[1] || 'UNKNOWN';
  const budget = parseInt(ad.daily_budget) || 15000;
  const budgetSEK = budget / 100;
  const ins = ad.insights?.data?.[0] || {};
  const spend = parseFloat(ins.spend) || 0;
  const impressions = parseInt(ins.impressions) || 0;
  const clicks = parseInt(ins.clicks) || 0;

  // ---- DYNAMIC: Leads from Meta API actions ----
  const metaLeads = getMetaLeads(ins);

  // ---- DYNAMIC: Quality from DB ----
  const qData = matchQuality(svc, leadQuality);
  const dbLeads = qData ? parseInt(qData.leads_7d) || 0 : 0;
  const qual = qData ? parseFloat(qData.avg_qual) || 0 : 0;

  // Primary: Meta leads. Fallback: DB leads.
  const leads = metaLeads > 0 ? metaLeads : dbLeads;
  const leadSrc = metaLeads > 0 ? 'Meta' : (dbLeads > 0 ? 'DB' : 'none');

  // CPL calculation (dynamic, based on real data)
  const cpl = leads > 0 ? Math.round(spend / leads) : (spend > 0 ? 9999 : 0);

  // Budget history (from DB)
  const hist = getCooldown(name, budgetHistory, CONFIG.MIN_DAYS_SINCE_CHANGE);

  // ==== CHECK 1: Cooldown ====
  if (hist.cooling) {
    summary.push('[COOLDOWN] ' + svc + ': ' + budgetSEK + ' kr | Cooldown (' + hist.days + 'd sedan senaste)');
    continue;
  }

  // ==== CHECK 2: Weekly change cap ====
  if (Math.abs(hist.totalPct) >= CONFIG.MAX_WEEKLY_TOTAL_CHANGE) {
    summary.push('[LOCK] ' + svc + ': ' + budgetSEK + ' kr | Veckotak natt (' + hist.totalPct.toFixed(0) + '%)');
    continue;
  }

  // ==== CHECK 3: Minimum data ====
  const hasMin = leads >= CONFIG.MIN_LEADS || spend >= CONFIG.TARGET_CPL * CONFIG.MIN_SPEND_FACTOR;
  if (!hasMin) {
    summary.push('[WAIT] ' + svc + ': ' + budgetSEK + ' kr | Learning (L:' + leads + ' Spend:' + spend.toFixed(0) + ' kr)');
    continue;
  }

  // ==== Calculate deviation ====
  let dev = 0;
  if (leads > 0) {
    dev = (cpl - CONFIG.TARGET_CPL) / CONFIG.TARGET_CPL;
  } else if (spend > CONFIG.TARGET_CPL) {
    dev = 1.0;
  }

  // ==== Decision logic ====
  let action = 'maintain';
  let newBudget = budget;
  let pct = 0;
  let reason = '';
  const capLeft = CONFIG.MAX_WEEKLY_TOTAL_CHANGE - Math.abs(hist.totalPct);

  // SAFETY: CPL > 2x target
  if (cpl > CONFIG.TARGET_CPL * CONFIG.PAUSE_CPL_MULTIPLIER && leads >= 2) {
    action = 'flag';
    reason = 'CPL ' + cpl + ' kr > ' + (CONFIG.TARGET_CPL * 2) + ' kr - Flaggad!';
  }
  // DECREASE: CPL 40%+ over target
  else if (dev > 0.40 && leads >= 2) {
    pct = -Math.min(15, capLeft);
    action = 'decrease';
    reason = 'CPL ' + cpl + ' kr (+' + Math.round(dev * 100) + '%) mycket over target';
  }
  // DECREASE: CPL 25-40% over target
  else if (dev > 0.25 && leads >= 2) {
    pct = -Math.min(10, capLeft);
    action = 'decrease';
    reason = 'CPL ' + cpl + ' kr (+' + Math.round(dev * 100) + '%) over target';
  }
  // DECREASE: CPL 15-25% over target
  else if (dev > CONFIG.NO_CHANGE_ZONE && leads >= 2) {
    pct = -Math.min(5, capLeft);
    action = 'decrease';
    reason = 'CPL ' + cpl + ' kr strax over target';
  }
  // DECREASE: 0 leads with significant spend
  else if (leads === 0 && spend > CONFIG.TARGET_CPL) {
    pct = -Math.min(10, capLeft);
    action = 'decrease';
    reason = '0 leads, spend ' + spend.toFixed(0) + ' kr';
  }
  // INCREASE: CPL 25%+ under target (excellent)
  else if (dev < -0.25 && leads >= 3) {
    pct = Math.min(15, capLeft);
    action = 'increase';
    reason = 'Bra CPL ' + cpl + ' kr (' + Math.round(dev * 100) + '%)';
  }
  // INCREASE: CPL 15-25% under target (good)
  else if (dev < -CONFIG.NO_CHANGE_ZONE && leads >= 2) {
    pct = Math.min(10, capLeft);
    action = 'increase';
    reason = 'CPL ' + cpl + ' kr under target';
  }
  // MAINTAIN: within dead zone
  else {
    reason = 'CPL ' + cpl + ' kr inom +/-15% av target (' + CONFIG.TARGET_CPL + ')';
  }

  // Apply change
  if (pct !== 0) {
    newBudget = Math.round(budget * (1 + pct / 100));
  }

  // Enforce absolute limits
  newBudget = Math.max(CONFIG.MIN_DAILY_BUDGET, Math.min(CONFIG.MAX_DAILY_BUDGET, newBudget));

  // Skip tiny changes
  if (Math.abs(newBudget - budget) < CONFIG.MIN_CHANGE_AMOUNT) {
    action = 'maintain';
    newBudget = budget;
    pct = 0;
  }

  // Build summary
  const labels = { increase: 'UP', decrease: 'DOWN', flag: 'FLAG', maintain: 'OK' };
  const lbl = labels[action] || 'OK';
  summary.push(
    '[' + lbl + '] ' + svc + ': ' + budgetSEK + ' -> ' + (newBudget / 100) + ' kr' +
    ' | L:' + leads + '(' + leadSrc + ')' +
    ' CPL:' + cpl +
    ' Dev:' + Math.round(dev * 100) + '%' +
    (qual > 0 ? ' Q:' + qual : '') +
    (pct !== 0 ? ' [' + (pct > 0 ? '+' : '') + pct + '%]' : '')
  );

  if (action !== 'maintain' && action !== 'flag') {
    results.push({
      id: ad.id,
      name: name,
      svc: svc,
      old: budget,
      new: newBudget,
      pct: pct,
      rsn: reason,
      cpl: cpl,
      leads: leads,
      leadSrc: leadSrc,
      qual: qual,
      spend: spend,
      deviation: Math.round(dev * 100)
    });
  }
}

// Footer
summary.push('');
summary.push('v3.0 Dynamic | Target: ' + CONFIG.TARGET_CPL + ' kr | Cooldown: ' + CONFIG.MIN_DAYS_SINCE_CHANGE + 'd | Cap: +/-' + CONFIG.MAX_WEEKLY_TOTAL_CHANGE + '%/vecka');
summary.push('Data: Meta Insights (leads, spend) + DB (kvalitet, historik)');

return [{ json: { updates: results, summary: summary.join('\n'), count: results.length } }];

const data = $input.first().json;
const results = data.updates || [];
const token = $env.FACEBOOK_USER_TOKEN;
const dbLogs = [];

for (const u of results) {
  try {
    const url = 'https://graph.facebook.com/v24.0/' + u.id + '?daily_budget=' + u.new + '&access_token=' + token;
    const resp = await this.helpers.httpRequest({ method: 'POST', url: url });
    if (resp.success) {
      dbLogs.push({
        old: u.old / 100,
        new: u.new / 100,
        change: u.pct,
        reason: u.name + ': ' + u.rsn,
        metrics: {
          cpl: u.cpl,
          leads: u.leads,
          leadSource: u.leadSrc,
          qual: u.qual,
          spend: u.spend,
          deviation: u.deviation
        }
      });
    }
  } catch (err) {
    dbLogs.push({
      old: u.old / 100,
      new: u.old / 100,
      change: 0,
      reason: u.name + ': ERROR - ' + (err.message || 'Unknown'),
      metrics: { cpl: u.cpl, leads: u.leads, error: true }
    });
  }
}

return [{ json: { summary: data.summary, dbLogs: dbLogs, changedAds: dbLogs.length } }];

